const jwt = require('jsonwebtoken');

const JWT_SECRET = 'your_jwt_secret'; // Replace with your actual secret
const ALLOWED_ALGORITHMS = ['HS256']; // Add allowed algorithms here

const authenticateJWT = (req, res, next) => {
    const token = req.headers['authorization']?.split(' ')[1];

    if (!token) {
        return res.sendStatus(401); // Unauthorized
    }

    jwt.verify(token, JWT_SECRET, { algorithms: ALLOWED_ALGORITHMS }, (err, user) => {
        if (err) {
            return res.sendStatus(403); // Forbidden
        }

        // Check for required claims
        if (!user.exp || user.exp < Math.floor(Date.now() / 1000)) {
            return res.sendStatus(401); // Token expired
        }

        req.user = user; // Attach user info to request
        next();
    });
};

module.exports = authenticateJWT;